create or replace function public.refresh_commission_preview_after_adjustment() returns trigger language plpgsql security definer set search_path to 'public' as $function$ declare target_month date; target_store_id uuid; begin if tg_op = 'DELETE' then target_month = old.month; select e.store_id into target_store_id from public.employees e where e.id = old.employee_id; target_store_id = coalesce(old.store_id, target_store_id); perform public.refresh_commission_preview(target_month, target_store_id); return old; end if; target_month = new.month; select e.store_id into target_store_id from public.employees e where e.id = new.employee_id; target_store_id = coalesce(new.store_id, target_store_id); perform public.refresh_commission_preview(target_month, target_store_id); return new; end; $function$;